import api from './api';
export default {
  async search(email) {
    const response = await api.request('search', 'QuoteCustomer', {
      email
    });
    return response.data || [];
  },
  async getByEmail(email) {
    const response = await api.request('getByEmail', 'QuoteCustomer', {
      email
    });
    return response.data;
  },
  async create(customer) {
    const response = await api.request('save', 'QuoteCustomer', {
      email: customer.email,
      name: customer.name,
      phone: customer.phone
    });
    return response.data;
  },
  async createOrUpdate(customer) {
    const response = await api.request('saveOrUpdate', 'QuoteCustomer', {
      email: customer.email,
      name: customer.name,
      phone: customer.phone
    });
    return response.data;
  }
};
